# **选择哪种渲染器**

一般来说，Canvas 更适合绘制图形元素数量较多（这一般是由数据量大导致）的图表（如热力图、地理坐标系或平行坐标系上的大规模线图或散点图等），也利于实现某些视觉 [特效](https://echarts.apache.org//examples/editor.html?c=lines-bmap-effect)。但是，在不少场景中，SVG 具有重要的优势：它的内存占用更低（这对移动端尤其重要）、并且用户使用浏览器内置的缩放功能时不会模糊。

选择哪种渲染器，我们可以根据软硬件环境、数据量、功能需求综合考虑。

- 在软硬件环境较好，数据量不大的场景下，两种渲染器都可以适用，并不需要太多纠结。

- 在环境较差，出现性能问题需要优化的场景下，可以通过试验来确定使用哪种渲染器。比如有这些经验：

  - 在须要创建很多 ECharts 实例且浏览器易崩溃的情况下（可能是因为 Canvas 数量多导致内存占用超出手机承受能力），可以使用 SVG 渲染器来进行改善。大略得说，如果图表运行在低端安卓机，或者我们在使用一些特定图表如 [水球图](https://ecomfe.github.io/echarts-liquidfill/example/) 等，SVG 渲染器可能效果更好。

  - 数据量较大（经验判断 \> 1k）、较多交互时，建议选择 Canvas 渲染器。

```javascript
// 使用 Canvas 渲染器（默认）
var chart = echarts.init(containerDom, null, { renderer: 'canvas' });
// 等价于：
var chart = echarts.init(containerDom);

// 使用 SVG 渲染器
var chart = echarts.init(containerDom, null, { renderer: 'svg' });
```

# 关闭动画效果

echart默认开启动画效果，关闭动画效果会显著提升渲染(视觉效果)

```javascript
echart.setOption({...options,animation:false})
```

在现代 Web 应用中，用户登录与身份验证是不可或缺的功能。Firebase 提供了完整的 Authentication 解决方案，支持多种登录方式（如 Google、Facebook、Apple、邮箱密码等），并与前端框架（如 React、Vue、Next.js）完美集成。

本文将封装一个通用的 **Firebase 登录方法**，支持多种登录方式、灵活的凭证输入，以及统一的类型定义。

## 一、准备工作

在开始之前，需要确保你已经完成以下步骤：

1. 已在 Firebase 控制台创建项目；

1. 启用了 Authentication 服务；

1. 添加了需要的登录提供商（如 Google、Facebook 等）；

1. 安装 Firebase SDK：

```shell
npm install firebase
```

## 二、封装

```typescript
import {
  getAuth,
  FacebookAuthProvider,
  signInWithPopup,
  GoogleAuthProvider,
  fetchSignInMethodsForEmail,
  signInWithEmailAndPassword,
  createUserWithEmailAndPassword,
  OAuthProvider,
  linkWithPopup,
  EmailAuthProvider,
  linkWithCredential,
  AuthCredential
} from "firebase/auth";

type ProviderId = "google.com" | "facebook.com" | "apple.com" | 'password';
// 支持两种传参：一是 OAuthTokens，二是已经构造好的 AuthCredential
type CredentialInput = OAuthTokens | AuthCredential;
interface OAuthTokens {
  idToken: string;
  accessToken?: string;
}
/**
 * 使用 Google 异步登录函数
 *
 * 此函数通过 Google 身份验证提供程序初始化登录流程，尝试使用弹出窗口让用户登录
 * 如果登录成功，返回包含用户信息的结果如果登录失败，返回错误信息
 *
 * @returns {Promise} 返回一个 Promise 对象，包含登录结果或错误信息
 */
export async function loginWithGoogle() {
  const auth = getAuth();
  // auth.languageCode = 'it';
  // To apply the default browser preference instead of explicitly setting it.
  // auth.useDeviceLanguage();
  const provider = new GoogleAuthProvider();
  try {
    const result = await signInWithPopup(auth, provider);
    return { data: result };
  } catch (error: any) {

    const errorInfo = {
      code: error.code,
      message: error.message,
      email: error.customData?.email,
      credential: GoogleAuthProvider.credentialFromError(error)
    };
    return {
      error,
      errorInfo
    }
  }
}

export async function loginWithPassword(email: string, password: string) {
  const auth = getAuth();
  const methods = await fetchSignInMethodsForEmail(auth, email);
  let result = null;
  try {
    if (methods.length) {
      result = await signInWithEmailAndPassword(auth, email, password);
    } else {
      result = await createUserWithEmailAndPassword(auth, email, password);
    }

    return { data: result };
  } catch (error: any) {
    const errorInfo = {
      code: error.code,
      message: error.message,
      email: error.customData?.email,
      credential: { providerId: "password" }
    };
    return { error, errorInfo };
  }
}

export async function loginWithFacebook() {
  const auth = getAuth();
  const provider = new FacebookAuthProvider();
  try {
    const result = await signInWithPopup(auth, provider);
    return { data: result };
  } catch (error: any) {
    const errorInfo = {
      code: error.code,
      message: error.message,
      email: error.customData?.email,
      credential: FacebookAuthProvider.credentialFromError(error)
    };
    return {
      error,
      errorInfo
    }
  }
}

export async function loginWithApple() {
  const auth = getAuth();
  const provider = new OAuthProvider('apple.com');
  try {
    const result = await signInWithPopup(auth, provider);
    return { data: result };
  } catch (error: any) {
    const errorInfo = {
      code: error.code,
      message: error.message,
      email: error.customData?.email,
      credential: OAuthProvider.credentialFromError(error)
    };
    return {
      error,
      errorInfo
    }
  }
}

export async function linkWithGoogle() {
  const provider = new GoogleAuthProvider();
  const auth = getAuth();
  if (!auth.currentUser) {
    return { error: 'No user currently signed in' };
  }
  try {
    const result = await linkWithPopup(auth.currentUser, provider)
    return { data: result };
  } catch (error) {
    return { error }
  }

}

