        credential = appleProvider.credential({
          idToken: tokens.idToken,
          accessToken: tokens.accessToken,
        });
        break;

      default:
        return { error: "Unsupported provider" };
    }
  }

  try {
    const result = await linkWithCredential(user, credential);
    return { data: result };
  } catch (error) {
    return { error };
  }
}
