export default function App() {
  return (
    <Suspense fallback={<div>Loading...</div>}>
      <UserPage />
    </Suspense>
  );
}

```

## 🧭 总结一下 `React.use()` 的作用：

👉 简单记法：

> React.use() = 渲染时“等待”Promise + Suspense 自动处理加载状态。

