});

stopBtn.addEventListener('click', () => {
  recorder.stop();
  // 延迟一点时间，确保 audioBlob 已生成
  setTimeout(() => {
    const url = recorder.getAudioUrl();
    if (url) {
      audioPlayer.src = url;
      audioPlayer.play();
    }
  }, 500);
