function evalRPN(tokens) {
    // 定义一个栈用于存储操作数
    const stack = [];

    // 定义运算符及其对应的计算方法
    const operators = {
        '+': (a, b) => a + b,
        '-': (a, b) => a - b,
        '*': (a, b) => a * b,
        '/': (a, b) => Math.trunc(a / b)
    };

